parameters.inputSchema:
{
  "type": "object",
  "required": ["title", "topics"],
  "properties": {
    "title": {
      "type": "string",
      "description": "A short, descriptive title"
    },
    "topics": {
      "type": "array",
      "description": "An array of exactly three topics",
      "minItems": 3,
      "maxItems": 3,
      "items": {
        "type": "string"
      }
    }
  }
}

{
  "type": "object",
  "properties": {
    "subject": {
      "type": "string",
      "description": "The email subject"
    },
    "content": {
      "type": "string",
      "description": "The newsletter content in HTML format"
    }
  },
  "required": ["subject", "content"]
}
